// Time:  O(n + 26)
// Space: O(26)

// freq table, greedy
class Solution {
public:
    string lexSmallestAfterDeletion(string s) {
        vector<int> cnt(26);
        for (const auto& x : s) {
            ++cnt[x - 'a'];
        }
        string result;
        for (int i = 0; i < size(s); ++i) {
            while (!empty(result) && result.back() > s[i] && cnt[result.back() - 'a'] != 1) {
                --cnt[result.back() - 'a'];
                result.pop_back();
            }
            result.push_back(s[i]);
        }
        while (cnt[result.back() - 'a'] != 1) {
            --cnt[result.back() - 'a'];
            result.pop_back();
        }
        return result;
    }
};

# Time:  O(n + 26)
# Space: O(26)

# freq table, greedy
class Solution(object):
    def lexSmallestAfterDeletion(self, s):
        """
        :type s: str
        :rtype: str
        """
        cnt = [0]*26
        for x in s:
            cnt[ord(x)-ord('a')] += 1
        result = []
        for x in s:
            while result and result[-1] > x and cnt[ord(result[-1])-ord('a')] != 1:
                cnt[ord(result[-1])-ord('a')] -= 1
                result.pop()
            result.append(x)
        while cnt[ord(result[-1])-ord('a')] != 1:
            cnt[ord(result[-1])-ord('a')] -= 1
            result.pop()
        return "".join(result)
